static inline void w_mstatus(uint64 x)
{
	asm volatile("csrw mstatus, %0" : : "r" (x));
}

void kvminithart()
{
	uint64 stap = SATP_SV39 | (((uint64)kernel_pagetable) >> 12);
	w_satp(stap);
	asm volatile("sfence.vma");
}

static inline void w_satp(uint64 x)
{
	asm volatile("csrw satp, %0" : : "r" (x));
}

void main(unsigned long hartid, unsigned long dtb_pa)
{
	cpuinit();
	floatinithart();
	consoleinit();
	kvminit();
	kvminithart();
	trapinithart();
	procinit();
	scheduler();
}

void consputc(int c) {
	if(c == BACKSPACE){
		sbi_console_putchar('\b');
		sbi_console_putchar(' ');
		sbi_console_putchar('\b');
	} else {
		sbi_console_putchar(c);
	}
}

void kvminit()
{
	kernel_pagetable = (pagetable_t) allocpage();
	kvmmap(UART_V, UART, PGSIZE, PTE_R | PTE_W);
}

static inline void floatinithart()
{
	w_sstatus_fs(SSTATUS_FS_INIT);
	w_frm(FRM_RNE);
	w_sstatus_fs(SSTATUS_FS_CLEAN);
}

void trapinithart(void)
{
	w_stvec((uint64)kernelvec);
	w_sstatus(r_sstatus() | SSTATUS_SIE);
	w_sie(r_sie() | SIE_SEIE | SIE_SSIE | SIE_STIE);
}

static inline void w_stvec(uint64 x)
{
	asm volatile("csrw stvec, %0" : : "r" (x));
}

void usertrapret(void) {
	w_stvec(TRAMPOLINE + (uservec - trampoline));
	w_sstatus(x & ~SSTATUS_SPP | SSTATUS_SPIE);
	w_sepc(p->trapframe->epc);
	uint64 satp = MAKE_SATP(p->pagetable);
	uint64 fn = TRAMPOLINE + (userret - trampoline);
	((void (*)(uint64, uint64))fn)((uint64)(p->trapframe), satp);
}

